import React from 'react';

import { games, images_sparkle } from '../constants';
import CollapsedVideoCard from '../components/combine/CollapsedVideoCard';
import { Container, Row, Col } from 'react-bootstrap';
import CustomCarousel from '../components/base/CustomCarousel';

function Home() {
  const sparkle = games[0];

  return (
    <div className='home-app'>
      <Container>
        <Row>
          <Col md={6}>
            <CollapsedVideoCard game={sparkle} />
          </Col>
          <Col md={6}>
            <CollapsedVideoCard game={sparkle} />
          </Col>
        </Row>
        <Row>
          <Col md={6}>
            <CollapsedVideoCard game={sparkle} />
          </Col>
          <Col md={6}>
            <CollapsedVideoCard game={sparkle} />
          </Col>
        </Row>
      </Container>

      <CustomCarousel images={images_sparkle} />
    </div>
  );
}

export default Home;
